// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract ContributionTracker {
    mapping(bytes32 => mapping(address => uint256)) public contributions;
    mapping(bytes32 => uint256) public totalContributions;

    event ContributionRecorded(
        bytes32 indexed workspaceId, 
        address contributor, 
        uint256 amount,
        string actionType
    );

    function recordContribution(
        bytes32 workspaceId,
        address contributor,
        uint256 amount,
        string memory actionType
    ) external {
        contributions[workspaceId][contributor] += amount;
        totalContributions[workspaceId] += amount;
        emit ContributionRecorded(workspaceId, contributor, amount, actionType);
    }

    function getContribution(
        bytes32 workspaceId, 
        address contributor
    ) external view returns (uint256) {
        return contributions[workspaceId][contributor];
    }

    function getSharePercentage(
        bytes32 workspaceId,
        address contributor
    ) external view returns (uint256) {
        uint256 total = totalContributions[workspaceId];
        if (total == 0) return 0;
        return (contributions[workspaceId][contributor] * 10000) / total;
    }
}

