// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./ContributionTracker.sol";

contract Treasury {
    ContributionTracker public tracker;
    mapping(bytes32 => uint256) public workspaceBalance;

    event RewardsDistributed(bytes32 indexed workspaceId, uint256 total);
    event Deposited(bytes32 indexed workspaceId, uint256 amount);

    constructor(address _tracker) {
        tracker = ContributionTracker(_tracker);
    }

    function deposit(bytes32 workspaceId) external payable {
        workspaceBalance[workspaceId] += msg.value;
        emit Deposited(workspaceId, msg.value);
    }

    function distributeRewards(
        bytes32 workspaceId,
        address[] memory contributors
    ) external {
        uint256 balance = workspaceBalance[workspaceId];
        require(balance > 0, "No balance");

        uint256 total = tracker.totalContributions(workspaceId);
        require(total > 0, "No contributions");

        for (uint i = 0; i < contributors.length; i++) {
            uint256 share = tracker.contributions(workspaceId, contributors[i]);
            uint256 payout = (balance * share) / total;
            if (payout > 0) {
                payable(contributors[i]).transfer(payout);
            }
        }
        workspaceBalance[workspaceId] = 0;
        emit RewardsDistributed(workspaceId, balance);
    }
}

