// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract WorkspaceRegistry {
    struct Member {
        address wallet;
        bytes32 anonymousId;
        string role;
        uint256 joinedAt;
    }

    struct Workspace {
        bytes32 id;
        string name;
        address owner;
        bool active;
        uint256 createdAt;
    }

    mapping(bytes32 => Workspace) public workspaces;
    mapping(bytes32 => Member[]) public workspaceMembers;
    mapping(bytes32 => mapping(address => bool)) public isMember;

    event WorkspaceCreated(bytes32 indexed id, string name, address owner);
    event MemberAdded(bytes32 indexed workspaceId, address member, string role);

    function createWorkspace(bytes32 id, string memory name) external {
        require(workspaces[id].createdAt == 0, "Workspace exists");
        workspaces[id] = Workspace(id, name, msg.sender, true, block.timestamp);
        isMember[id][msg.sender] = true;
        emit WorkspaceCreated(id, name, msg.sender);
    }

    function addMember(
        bytes32 workspaceId, 
        address member, 
        bytes32 anonymousId,
        string memory role
    ) external {
        require(workspaces[workspaceId].owner == msg.sender, "Not owner");
        require(!isMember[workspaceId][member], "Already member");
        workspaceMembers[workspaceId].push(
            Member(member, anonymousId, role, block.timestamp)
        );
        isMember[workspaceId][member] = true;
        emit MemberAdded(workspaceId, member, role);
    }

    function getMemberCount(bytes32 workspaceId) external view returns (uint256) {
        return workspaceMembers[workspaceId].length;
    }
}

